import { PropsSchema } from './schema';
import { generateControls } from './lib/types';

export const controls = generateControls(PropsSchema, {
  groups: {
    Content: ['kind', 'points'],
    Style: [
      // Stroke 描边
      'stroke',
      'strokeWidth',
      'strokeStyle',
      'sloppiness',
      // Arrow 箭头
      'arrowType',
      'arrowStart',
      'arrowEnd',
      'arrowSize',
      // Opacity 透明度
      'opacity',
    ],
    Data: [
      // Node Binding 节点连接
      'sourceNodeId',
      'sourceAnchor',
      'targetNodeId',
      'targetAnchor',
    ],
    Advanced: [
      'lineCap',
      // Flow 流动
      'flowEnabled',
      'flowSpeed',
      'flowSpacing',
      // Legacy
      'direction',
      'dashPattern',
    ],
  },
  overrides: {
    stroke: { kind: 'color' },
    points: { kind: 'json' },
    sourceNodeId: { kind: 'nodeSelect', label: '起点节点' },
    targetNodeId: { kind: 'nodeSelect', label: '终点节点' },
  },
});
